/**
 * Disbursement Details Modal
 *
 * Click-to-view popup for disbursement transactions.
 */
import React from 'react';
import { createPortal } from 'react-dom';

const formatDateTime = (dateString) => {
  if (!dateString) { return '—'; }
  const d = new Date(dateString);
  if (Number.isNaN(d.getTime())) { return String(dateString); }
  return d.toLocaleString('en-US', {
    year: 'numeric', month: 'short', day: 'numeric',
    hour: '2-digit', minute: '2-digit',
  });
};

const CopyButton = ({ value }) => {
  const canCopy = typeof navigator !== 'undefined' && !!navigator.clipboard?.writeText;
  if (!value || !canCopy) { return null; }
  return (
    <button
      type="button"
      onClick={(e) => { e.stopPropagation(); navigator.clipboard.writeText(String(value)); }}
      style={{
        border: '1px solid var(--border-primary)',
        background: 'var(--bg-input)',
        color: 'var(--text-muted)',
        borderRadius: 8,
        padding: '3px 8px',
        cursor: 'pointer',
        fontSize: 11,
        display: 'inline-flex',
        alignItems: 'center',
        gap: 4,
        marginLeft: 6,
        verticalAlign: 'middle',
      }}
    >
      <span className="material-symbols-outlined" style={{ fontSize: 13 }}>content_copy</span>
    </button>
  );
};

const Row = ({ label, value, copyable, mono }) => {
  if (!value && value !== 0) { return null; }
  return (
    <div style={{
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'flex-start',
      padding: '11px 0',
      borderBottom: '1px solid var(--border-primary)',
      gap: '16px',
    }}>
      <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)', flexShrink: 0, minWidth: '110px' }}>
        {label}
      </span>
      <span style={{
        fontSize: '0.875rem',
        fontWeight: '500',
        color: 'var(--text-primary)',
        textAlign: 'right',
        wordBreak: 'break-word',
        fontFamily: mono ? 'monospace' : undefined,
      }}>
        {String(value)}
        {copyable && <CopyButton value={value} />}
      </span>
    </div>
  );
};

const StatusBadge = ({ status }) => {
  const s = (status || '').toLowerCase();
  const map = {
    success: { bg: 'var(--success-bg)', color: 'var(--success)', label: 'Success' },
    failed:  { bg: 'var(--error-bg)',   color: 'var(--error)',   label: 'Failed'  },
    pending: { bg: 'var(--warning-bg)', color: 'var(--warning)', label: 'Pending' },
  };
  const cfg = map[s] || map.pending;
  return (
    <span style={{
      display: 'inline-block',
      padding: '3px 10px',
      borderRadius: '6px',
      fontSize: '0.8rem',
      fontWeight: '700',
      background: cfg.bg,
      color: cfg.color,
      textTransform: 'capitalize',
    }}>
      {cfg.label}
    </span>
  );
};

const DisbursementDetailsModal = ({ open, onClose, payout }) => {
  if (!open || !payout) { return null; }

  const isSuccess = (payout.status || '').toLowerCase() === 'success';
  const isFailed  = (payout.status || '').toLowerCase() === 'failed';

  return createPortal(
    <div
      onClick={(e) => { if (e.target === e.currentTarget) { onClose(); } }}
      style={{
        position: 'fixed',
        inset: 0,
        backgroundColor: 'rgba(0,0,0,0.5)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 10050,
        backdropFilter: 'blur(4px)',
        padding: 16,
      }}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          width: '100%',
          maxWidth: 480,
          maxHeight: '88vh',
          overflowY: 'auto',
          backgroundColor: 'var(--card)',
          borderRadius: 16,
          border: '1px solid var(--border-primary)',
          boxShadow: 'var(--shadow-xl)',
        }}
      >
        {/* Header */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: '18px 20px 14px',
          borderBottom: '1px solid var(--border-primary)',
          position: 'sticky',
          top: 0,
          background: 'var(--card)',
          zIndex: 1,
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <span className="material-symbols-outlined" style={{ fontSize: 22, color: 'var(--accent)' }}>
              receipt_long
            </span>
            <div>
              <div style={{ fontWeight: 700, color: 'var(--text-primary)', fontSize: '1rem' }}>
                Transaction Details
              </div>
              <div style={{ color: 'var(--text-muted)', fontSize: '0.75rem', fontFamily: 'monospace', marginTop: 2 }}>
                {payout.reference}
              </div>
            </div>
          </div>
          <button
            type="button"
            onClick={onClose}
            style={{
              border: 'none',
              background: 'none',
              color: 'var(--text-muted)',
              cursor: 'pointer',
              padding: 4,
              display: 'flex',
              alignItems: 'center',
            }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: 22 }}>close</span>
          </button>
        </div>

        {/* Amount hero */}
        <div style={{
          textAlign: 'center',
          padding: '20px 20px 16px',
          background: isSuccess ? 'var(--success-bg)' : isFailed ? 'var(--error-bg)' : 'var(--warning-bg)',
          borderBottom: '1px solid var(--border-primary)',
        }}>
          <div style={{
            fontSize: '2rem',
            fontWeight: '800',
            color: isSuccess ? 'var(--success)' : isFailed ? 'var(--error)' : 'var(--warning)',
          }}>
            {payout.amount}
          </div>
          <div style={{ marginTop: 8 }}>
            <StatusBadge status={payout.status} />
          </div>
          {payout.narration && (
            <div style={{ marginTop: 8, fontSize: '0.85rem', color: 'var(--text-muted)' }}>
              {payout.narration}
            </div>
          )}
        </div>

        {/* Detail rows */}
        <div style={{ padding: '4px 20px 20px' }}>
          <Row label="Reference"       value={payout.reference}    copyable mono />
          <Row label="Transaction ID"  value={payout.transactionId} copyable mono />
          <Row label="Type"            value={payout.itemType} />
          <Row label="Channel"         value={(payout.channel || '').replace(/_/g, ' ')} />
          <Row label="Disburse Type"   value={payout.disburseType !== 'utility' ? payout.disburseType?.replace(/_/g, ' ') : null} />
          <Row label="Currency"        value={payout.currency} />
          <Row label="Provider Ref"    value={payout.providerRef}  copyable mono />
          <Row label="Source"          value={payout.source} />
          {/* Utility-specific */}
          {payout.destination && <Row label="Destination" value={payout.destination} />}
          {payout.requestDetails?.ProductCode && <Row label="Product Code" value={payout.requestDetails.ProductCode} />}
          {payout.requestDetails?.serviceId && <Row label="Service ID" value={payout.requestDetails.serviceId} mono copyable />}
          <Row label="Created"         value={formatDateTime(payout.createdAt)} />
          <Row label="Updated"         value={formatDateTime(payout.updatedAt)} />
          {(payout.errorCode || payout.errorMessage) && (
            <div style={{
              marginTop: 12,
              padding: '12px 14px',
              background: 'var(--error-bg)',
              borderRadius: 10,
              border: '1px solid var(--error)',
            }}>
              <div style={{ fontSize: '0.75rem', fontWeight: '700', color: 'var(--error)', marginBottom: 4 }}>
                Error Details
              </div>
              {payout.errorCode && (
                <div style={{ fontSize: '0.8rem', color: 'var(--text-primary)' }}>
                  Code: {payout.errorCode}
                </div>
              )}
              {payout.errorMessage && (
                <div style={{ fontSize: '0.8rem', color: 'var(--text-primary)', marginTop: 4 }}>
                  {payout.errorMessage}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Close button */}
        <div style={{ padding: '0 20px 20px' }}>
          <button
            type="button"
            onClick={onClose}
            style={{
              width: '100%',
              padding: '12px',
              borderRadius: 10,
              border: 'none',
              background: 'var(--accent)',
              color: 'var(--text-inverse)',
              fontWeight: '600',
              fontSize: '0.9rem',
              cursor: 'pointer',
            }}
          >
            Close
          </button>
        </div>
      </div>
    </div>,
    document.body
  );
};

export default DisbursementDetailsModal;
